import React, { useEffect, useMemo, useRef, useState } from 'react';
import {
  AlertCircle,
  Banknote,
  CheckCircle2,
  CreditCard,
  Expand,
  Loader,
  Minus,
  Minimize2,
  Package,
  Plus,
  ReceiptText,
  Search,
  ShoppingCart,
  Trash2,
  X,
} from 'lucide-react';
import api from '../../services/api';
import { toAbsoluteImageUrl } from '../../utils/imageUrl';

const formatCurrency = (value) =>
  new Intl.NumberFormat('en-US', {
    style: 'currency',
    currency: 'USD',
    minimumFractionDigits: 2,
  }).format(Number(value || 0));

const getProductPrice = (product) => Number(product?.sellingPrice ?? product?.price ?? 0);
const getProductStock = (product) => Number(product?.stockQty ?? product?.stockQuantity ?? 0);

const keypadDigits = ['1', '2', '3', '4', '5', '6', '7', '8', '9', '0'];

const StaffPOS = () => {
  const [products, setProducts] = useState([]);
  const [categories, setCategories] = useState([]);
  const [cart, setCart] = useState([]);
  const [search, setSearch] = useState('');
  const [activeCategory, setActiveCategory] = useState('all');
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [successMsg, setSuccessMsg] = useState('');
  const [paying, setPaying] = useState(false);
  const [payMethod, setPayMethod] = useState('Cash');
  const [selectedProduct, setSelectedProduct] = useState(null);
  const [modalQty, setModalQty] = useState(1);
  const [selectedCartItemId, setSelectedCartItemId] = useState(null);
  const [qtyInput, setQtyInput] = useState('');
  const [isFullscreen, setIsFullscreen] = useState(false);
  const [compactMode, setCompactMode] = useState(true);
  const containerRef = useRef(null);

  useEffect(() => {
    let mounted = true;

    const fetchData = async () => {
      try {
        setError('');
        const [productsRes, categoriesRes] = await Promise.allSettled([
          api.get('/products'),
          api.get('/categories'),
        ]);

        if (!mounted) {
          return;
        }

        const productItems = productsRes.status === 'fulfilled' && Array.isArray(productsRes.value?.data)
          ? productsRes.value.data
          : [];

        const categoryItems = categoriesRes.status === 'fulfilled' && Array.isArray(categoriesRes.value?.data)
          ? categoriesRes.value.data
          : [];

        setProducts(productItems.sort((left, right) => (left.productName || '').localeCompare(right.productName || '')));
        setCategories(categoryItems);
      } catch {
        if (mounted) {
          setError('Failed to load products.');
        }
      } finally {
        if (mounted) {
          setLoading(false);
        }
      }
    };

    fetchData();

    return () => {
      mounted = false;
    };
  }, []);

  useEffect(() => {
    if (!error && !successMsg) {
      return undefined;
    }

    const timer = window.setTimeout(() => {
      setError('');
      setSuccessMsg('');
    }, 3500);

    return () => window.clearTimeout(timer);
  }, [error, successMsg]);

  useEffect(() => {
    const handleFullscreenChange = () => {
      setIsFullscreen(Boolean(document.fullscreenElement));
    };

    document.addEventListener('fullscreenchange', handleFullscreenChange);
    return () => document.removeEventListener('fullscreenchange', handleFullscreenChange);
  }, []);

  const categoryChips = useMemo(() => {
    const map = new Map();

    categories.forEach((category) => {
      const id = String(category?.categoryId ?? category?.id ?? '');
      const name = category?.categoryName || category?.name;

      if (id && name) {
        map.set(id, { id, name });
      }
    });

    products.forEach((product) => {
      const id = String(product?.categoryId ?? product?.category?.categoryId ?? '');
      const name = product?.category?.categoryName || product?.categoryName;

      if (id && name && !map.has(id)) {
        map.set(id, { id, name });
      }
    });

    return [{ id: 'all', name: 'All' }, ...Array.from(map.values()).sort((left, right) => left.name.localeCompare(right.name))];
  }, [categories, products]);

  const categoryNameMap = useMemo(() => {
    const map = new Map();
    categoryChips.forEach((chip) => {
      if (chip.id !== 'all') {
        map.set(chip.id, chip.name);
      }
    });
    return map;
  }, [categoryChips]);

  const getCategoryName = (product) => {
    const fromRelation = product?.category?.categoryName || product?.categoryName;
    if (fromRelation) {
      return fromRelation;
    }

    const id = String(product?.categoryId ?? product?.category?.categoryId ?? '');
    return categoryNameMap.get(id) || 'Uncategorized';
  };

  const getCategoryId = (product) => String(product?.categoryId ?? product?.category?.categoryId ?? '');

  const categoryCounts = useMemo(() => {
    const counts = new Map();
    products.forEach((product) => {
      const id = getCategoryId(product);
      if (!id) return;
      counts.set(id, (counts.get(id) || 0) + 1);
    });
    return counts;
  }, [products]);

  const filteredProducts = useMemo(() => {
    const query = search.trim().toLowerCase();

    return products.filter((product) => {
      const matchesCategory = activeCategory === 'all' || getCategoryId(product) === activeCategory;
      const matchesSearch = !query
        || (product.productName || '').toLowerCase().includes(query)
        || (product.barcode || '').toLowerCase().includes(query);

      return matchesCategory && matchesSearch;
    });
  }, [activeCategory, products, search]);

  const selectedCartItem = useMemo(
    () => cart.find((item) => item.productId === selectedCartItemId) || null,
    [cart, selectedCartItemId],
  );

  const cartCount = useMemo(() => cart.reduce((count, item) => count + item.qty, 0), [cart]);
  const subtotal = useMemo(
    () => cart.reduce((total, item) => total + getProductPrice(item) * item.qty, 0),
    [cart],
  );

  const showFeedback = (message, type = 'success') => {
    if (type === 'error') {
      setSuccessMsg('');
      setError(message);
      return;
    }

    setError('');
    setSuccessMsg(message);
  };

  const addToCart = (product, quantity = 1) => {
    const stock = getProductStock(product);
    const amount = Math.max(1, Number(quantity) || 1);

    if (stock <= 0) {
      showFeedback('This product is out of stock.', 'error');
      return;
    }

    setCart((currentCart) => {
      const existing = currentCart.find((item) => item.productId === product.productId);
      const nextQty = (existing?.qty || 0) + amount;

      if (nextQty > stock) {
        showFeedback(`Only ${stock} item(s) available in stock.`, 'error');
        return currentCart;
      }

      if (existing) {
        return currentCart.map((item) => (
          item.productId === product.productId
            ? { ...item, qty: nextQty }
            : item
        ));
      }

      return [...currentCart, { ...product, qty: amount }];
    });

    setSelectedCartItemId(product.productId);
    setQtyInput('');
    showFeedback(`${product.productName || 'Item'} added to cart.`);
  };

  const updateItemQty = (productId, nextQty) => {
    setCart((currentCart) => currentCart.reduce((items, item) => {
      if (item.productId !== productId) {
        items.push(item);
        return items;
      }

      const stock = getProductStock(item);
      const safeQty = Math.min(Math.max(0, Number(nextQty) || 0), stock);

      if (safeQty <= 0) {
        return items;
      }

      items.push({ ...item, qty: safeQty });
      return items;
    }, []));
  };

  const changeQty = (productId, delta) => {
    const cartItem = cart.find((item) => item.productId === productId);
    if (!cartItem) {
      return;
    }

    const nextQty = cartItem.qty + delta;
    const stock = getProductStock(cartItem);

    if (nextQty > stock) {
      showFeedback(`Only ${stock} item(s) available in stock.`, 'error');
      return;
    }

    updateItemQty(productId, nextQty);
    setSelectedCartItemId(productId);
  };

  const removeItem = (productId) => {
    setCart((currentCart) => currentCart.filter((item) => item.productId !== productId));

    if (selectedCartItemId === productId) {
      setSelectedCartItemId(null);
      setQtyInput('');
    }
  };

  const clearCart = () => {
    setCart([]);
    setSelectedCartItemId(null);
    setQtyInput('');
  };

  const openProductModal = (product) => {
    setSelectedProduct(product);
    setModalQty(1);
  };

  const closeProductModal = () => {
    setSelectedProduct(null);
    setModalQty(1);
  };

  const applyKeypadQuantity = () => {
    if (!selectedCartItem || !qtyInput) {
      return;
    }

    const requestedQty = Number(qtyInput);
    const stock = getProductStock(selectedCartItem);

    if (requestedQty > stock) {
      showFeedback(`Only ${stock} item(s) available in stock.`, 'error');
      return;
    }

    updateItemQty(selectedCartItem.productId, requestedQty);
    setQtyInput('');
    showFeedback('Cart quantity updated.');
  };

  const handleKeypadPress = (value) => {
    setQtyInput((current) => (current === '0' ? value : `${current}${value}`).slice(0, 3));
  };

  const handleCheckout = async () => {
    if (cart.length === 0 || paying) {
      return;
    }

    setPaying(true);

    try {
      await api.post('/sales', {
        saleDetails: cart.map((item) => ({
          productId: item.productId,
          quantity: item.qty,
          unitPrice: getProductPrice(item),
        })),
        paymentMethod: payMethod,
        amountTendered: subtotal,
      });

      clearCart();
      showFeedback('Sale completed successfully.');
    } catch {
      showFeedback('Failed to process sale. Try again.', 'error');
    } finally {
      setPaying(false);
    }
  };

  const toggleFullscreen = async () => {
    try {
      if (!document.fullscreenElement) {
        await containerRef.current?.requestFullscreen();
      } else {
        await document.exitFullscreen();
      }
    } catch {
      showFeedback('Fullscreen is not available on this browser.', 'error');
    }
  };

  return (
    <div
      ref={containerRef}
      className={`${isFullscreen ? 'h-screen rounded-none p-2 sm:p-3' : 'h-[calc(100vh-156px)] min-h-[640px] rounded-none p-3 sm:p-4 lg:p-5'} bg-[radial-gradient(circle_at_top_left,_rgba(59,130,246,0.16),_transparent_34%),radial-gradient(circle_at_bottom_right,_rgba(16,185,129,0.16),_transparent_30%),linear-gradient(180deg,_#f6f9ff_0%,_#eef4ff_52%,_#e9f7f3_100%)]`}
    >
      <div className={`grid h-full min-h-0 gap-4 ${compactMode ? 'lg:grid-cols-[minmax(0,1fr)_350px] xl:grid-cols-[minmax(0,1fr)_380px]' : 'lg:grid-cols-[minmax(0,1fr)_400px] 2xl:grid-cols-[minmax(0,1fr)_440px]'}`}>
        <section className="flex min-h-0 flex-col overflow-hidden rounded-none border border-white/80 bg-white/85 shadow-[0_24px_80px_rgba(15,23,42,0.1)] backdrop-blur-md">
          <div className={`${compactMode ? 'px-3 py-3 sm:px-4' : 'px-4 py-4 sm:px-6'} border-b border-slate-200/80 bg-white/70 backdrop-blur`}>
            <div className="flex flex-col gap-4 lg:flex-row lg:items-center lg:justify-between">
              <div>
                <p className="text-[11px] font-bold uppercase tracking-[0.28em] text-blue-700/80">Sell / POS</p>
                <h1 className="mt-1 text-2xl font-black tracking-tight text-slate-900 sm:text-3xl">Fast checkout for the counter</h1>
              </div>
              <div className="flex items-center justify-end gap-2">
                <button
                  type="button"
                  onClick={() => setCompactMode((previous) => !previous)}
                  className="inline-flex items-center gap-1.5 rounded-none border border-slate-200 bg-white px-3 py-2 text-xs font-semibold text-slate-700 transition hover:border-blue-300 hover:bg-blue-50 hover:text-blue-700"
                >
                  {compactMode ? 'Comfort' : 'Compact'}
                </button>
                <button
                  type="button"
                  onClick={toggleFullscreen}
                  className="inline-flex items-center gap-1.5 rounded-none border border-slate-200 bg-white px-3 py-2 text-xs font-semibold text-slate-700 transition hover:border-blue-300 hover:bg-blue-50 hover:text-blue-700"
                >
                  {isFullscreen ? <Minimize2 className="w-4 h-4" /> : <Expand className="w-4 h-4" />}
                  {isFullscreen ? 'Exit Fullscreen' : 'Fullscreen'}
                </button>
              </div>
            </div>

            <div className="relative mt-4">
              <Search className="absolute w-5 h-5 -translate-y-1/2 pointer-events-none left-4 top-1/2 text-slate-400" />
              <input
                value={search}
                onChange={(event) => setSearch(event.target.value)}
                placeholder="Scan barcode or search name..."
                className="w-full pl-12 pr-4 text-base transition bg-white border rounded-none outline-none h-14 border-slate-200 text-slate-800 focus:border-blue-300 focus:ring-4 focus:ring-blue-100"
              />
            </div>

            <div className="flex gap-3 pb-1 mt-4 overflow-x-auto">
              {categoryChips.map((category) => {
                const isActive = category.id === activeCategory;
                const count = category.id === 'all' ? products.length : (categoryCounts.get(category.id) || 0);

                return (
                  <button
                    key={category.id}
                    type="button"
                    onClick={() => setActiveCategory(category.id)}
                    className={`whitespace-nowrap rounded-none border px-4 py-2.5 text-sm font-semibold transition ${isActive ? 'border-blue-600 bg-blue-600 text-white shadow-[0_10px_24px_rgba(37,99,235,0.28)]' : 'border-slate-200 bg-white text-slate-700 hover:border-blue-200 hover:bg-blue-50 hover:text-blue-700'}`}
                  >
                    {category.name} ({count})
                  </button>
                );
              })}
            </div>
          </div>

          <div className="flex-1 min-h-0 px-4 py-4 overflow-y-auto sm:px-6">
            {(error || successMsg) && (
              <div className={`mb-4 flex items-center gap-2 rounded-none border px-4 py-3 text-sm font-medium ${error ? 'border-red-200 bg-red-50 text-red-700' : 'border-emerald-200 bg-emerald-50 text-emerald-700'}`}>
                {error ? <AlertCircle className="flex-shrink-0 w-4 h-4" /> : <CheckCircle2 className="flex-shrink-0 w-4 h-4" />}
                <span>{error || successMsg}</span>
              </div>
            )}

            {loading ? (
              <div className="flex items-center justify-center h-72 text-slate-400">
                <Loader className="w-8 h-8 animate-spin" />
              </div>
            ) : filteredProducts.length === 0 ? (
              <div className="flex flex-col items-center justify-center text-center border border-dashed rounded-none h-72 border-slate-200 bg-slate-50 text-slate-400">
                <Package className="w-10 h-10 mb-3" />
                <p className="text-lg font-semibold text-slate-600">No products found</p>
                <p className="mt-1 text-sm">Try another search or switch category.</p>
              </div>
            ) : (
              <div className={`grid gap-4 ${compactMode ? 'sm:grid-cols-2 xl:grid-cols-3' : 'sm:grid-cols-2 xl:grid-cols-3 2xl:grid-cols-4'}`}>
                {filteredProducts.map((product) => {
                  const stock = getProductStock(product);
                  const imageUrl = toAbsoluteImageUrl(product.imageUrl);

                  return (
                    <button
                      key={product.productId}
                      type="button"
                      onClick={() => openProductModal(product)}
                      className="group overflow-hidden rounded-none border border-slate-200/90 bg-white text-left shadow-[0_10px_24px_rgba(15,23,42,0.06)] transition duration-200 hover:-translate-y-1 hover:border-blue-300 hover:shadow-[0_18px_45px_rgba(37,99,235,0.16)]"
                    >
                      <div className={`relative overflow-hidden bg-[linear-gradient(135deg,_#eff6ff_0%,_#f8fafc_55%,_#ecfeff_100%)] ${compactMode ? 'h-28' : 'h-36'}`}>
                        {imageUrl ? (
                          <img src={imageUrl} alt={product.productName} className="object-cover w-full h-full transition duration-300 group-hover:scale-105" />
                        ) : (
                          <div className="flex items-center justify-center h-full text-slate-300">
                            <Package className="w-10 h-10" />
                          </div>
                        )}
                        <div className="absolute px-3 py-1 text-xs font-semibold rounded-none shadow-sm left-3 top-3 bg-white/95 text-slate-700">
                          {getCategoryName(product)}
                        </div>
                      </div>

                      <div className={`${compactMode ? 'p-3 space-y-1.5' : 'p-4 space-y-2'}`}>
                        <div>
                          <h2 className={`${compactMode ? 'text-base' : 'text-lg'} font-bold line-clamp-1 text-slate-900`}>{product.productName}</h2>
                          <p className="mt-1 line-clamp-1 text-xs uppercase tracking-[0.18em] text-slate-400">
                            {product.barcode || 'No barcode'}
                          </p>
                        </div>

                        <div className="flex items-end justify-between gap-3 pt-2 border-t border-slate-100">
                          <div>
                            <p className="text-[10px] uppercase tracking-[0.22em] text-slate-400">Price</p>
                            <p className={`${compactMode ? 'text-xl' : 'text-2xl'} font-black text-blue-600`}>{formatCurrency(getProductPrice(product))}</p>
                          </div>
                          <div className={`rounded-none border px-3 py-1 text-xs font-semibold ${stock > 0 ? 'border-emerald-100 bg-emerald-50 text-emerald-700' : 'border-red-100 bg-red-50 text-red-700'}`}>
                            Stock: {stock}
                          </div>
                        </div>
                      </div>
                    </button>
                  );
                })}
              </div>
            )}
          </div>
        </section>

        <aside className="flex min-h-0 flex-col overflow-hidden rounded-none border border-white/80 bg-white/95 shadow-[0_24px_80px_rgba(15,23,42,0.14)] backdrop-blur-md">
          <div className="px-4 py-4 border-b border-slate-200 sm:px-5">
            <div className="flex items-center justify-between">
              <div className="flex items-center gap-3">
                <div className="rounded-none bg-blue-50 p-2.5 text-blue-600">
                  <ShoppingCart className="w-6 h-6" />
                </div>
                <div>
                  <h2 className="text-2xl font-black tracking-tight text-slate-900">Cart</h2>
                  <p className="text-sm text-slate-500">Tap an item to adjust it</p>
                </div>
              </div>
              <div className="flex h-10 min-w-10 items-center justify-center rounded-none bg-blue-600 px-3 text-sm font-bold text-white shadow-[0_8px_20px_rgba(37,99,235,0.35)]">
                {cartCount}
              </div>
            </div>
          </div>

          <div className="grid grid-cols-[60px_minmax(120px,1fr)_70px_76px_86px] gap-2 border-b border-slate-100 px-4 py-2 text-[10px] font-bold uppercase tracking-[0.16em] text-slate-400 sm:px-5">
            <span>Image</span>
            <span>Name</span>
            <span className="text-center">Qty</span>
            <span className="text-right">Price</span>
            <span className="text-right">Total</span>
          </div>

          <div className="flex-1 min-h-0 px-4 py-2 overflow-auto sm:px-5">
            {cart.length === 0 ? (
              <div className="flex flex-col items-center justify-center h-full px-6 text-center border border-dashed rounded-none border-slate-200 bg-slate-50 text-slate-400">
                <ShoppingCart className="mb-4 h-14 w-14" />
                <p className="text-xl font-bold text-slate-600">Cart is empty</p>
                <p className="mt-2 text-sm">Select a product from the left to start the sale.</p>
              </div>
            ) : (
              <div className="min-w-[450px] space-y-1.5">
                {cart.map((item) => {
                  const imageUrl = toAbsoluteImageUrl(item.imageUrl);
                  const lineTotal = getProductPrice(item) * item.qty;
                  const selected = selectedCartItemId === item.productId;

                  return (
                    <button
                      key={item.productId}
                      type="button"
                      onClick={() => setSelectedCartItemId(item.productId)}
                      className={`grid w-full grid-cols-[60px_minmax(120px,1fr)_70px_76px_86px_auto] items-center gap-2 rounded-none border px-2 py-2 text-left transition ${selected ? 'border-blue-300 bg-blue-50/60 shadow-[0_8px_24px_rgba(59,130,246,0.15)]' : 'border-slate-200 bg-white hover:border-blue-200'}`}
                    >
                      <div className="overflow-hidden rounded-none h-11 w-11 bg-slate-100">
                        {imageUrl ? (
                          <img src={imageUrl} alt={item.productName} className="object-cover w-full h-full" />
                        ) : (
                          <div className="flex items-center justify-center h-full text-slate-300">
                            <Package className="w-5 h-5" />
                          </div>
                        )}
                      </div>

                      <div className="min-w-0 pr-1">
                        <p className="text-sm font-bold truncate text-slate-900">{item.productName}</p>
                        <p className="mt-0.5 text-[11px] text-slate-500">{getCategoryName(item)}</p>
                      </div>

                      <div className="flex items-center justify-center gap-1.5">
                        <span className="inline-flex items-center justify-center w-6 h-6 bg-white border rounded-none border-slate-200 text-slate-500">
                          <Minus className="w-3 h-3" />
                        </span>
                        <span className="w-4 text-sm font-bold text-center text-slate-900">{item.qty}</span>
                        <span className="inline-flex items-center justify-center w-6 h-6 text-blue-600 border border-blue-200 rounded-none bg-blue-50">
                          <Plus className="w-3 h-3" />
                        </span>
                      </div>

                      <div className="text-sm font-semibold text-right text-slate-700">{formatCurrency(getProductPrice(item))}</div>
                      <div className="text-base font-black text-right text-slate-900">{formatCurrency(lineTotal)}</div>

                      <div className="flex items-center gap-1">
                        <button
                          type="button"
                          onClick={(event) => {
                            event.stopPropagation();
                            changeQty(item.productId, -1);
                          }}
                          className="inline-flex items-center justify-center bg-white border rounded-none h-7 w-7 border-slate-200 text-slate-600 hover:border-slate-300"
                        >
                          <Minus className="h-3.5 w-3.5" />
                        </button>
                        <button
                          type="button"
                          onClick={(event) => {
                            event.stopPropagation();
                            changeQty(item.productId, 1);
                          }}
                          className="inline-flex items-center justify-center text-blue-600 border border-blue-200 rounded-none h-7 w-7 bg-blue-50 hover:border-blue-300"
                        >
                          <Plus className="h-3.5 w-3.5" />
                        </button>
                        <button
                          type="button"
                          onClick={(event) => {
                            event.stopPropagation();
                            removeItem(item.productId);
                          }}
                          className="inline-flex items-center justify-center rounded-none h-7 w-7 text-slate-300 hover:bg-red-50 hover:text-red-500"
                        >
                          <X className="h-3.5 w-3.5" />
                        </button>
                      </div>
                    </button>
                  );
                })}
              </div>
            )}
          </div>

          <div className="border-t border-slate-200 bg-white px-4 py-3 sm:px-5">
            <div className="flex items-center justify-between border-b border-slate-100 pb-3">
              <span className="text-xl font-black text-slate-900">Total:</span>
              <span className="text-3xl font-black tracking-tight text-blue-600">{formatCurrency(subtotal)}</span>
            </div>

            <div className="mt-3 text-center">
              <p className="text-xs text-slate-400">Qty: <span className="font-bold text-blue-600">{qtyInput || selectedCartItem?.qty || '-'}</span></p>
              {selectedCartItem && (
                <p className="mt-1 truncate text-[11px] text-slate-500">Selected: {selectedCartItem.productName}</p>
              )}
            </div>

            <div className="mt-3 grid grid-cols-5 gap-1.5">
              {keypadDigits.slice(0, 5).map((digit) => (
                <button
                  key={digit}
                  type="button"
                  onClick={() => handleKeypadPress(digit)}
                  className="rounded-none border border-slate-200 bg-white py-2 text-xl font-bold text-slate-900 transition hover:border-blue-200 hover:text-blue-600"
                >
                  {digit}
                </button>
              ))}
              {keypadDigits.slice(5, 10).map((digit) => (
                <button
                  key={digit}
                  type="button"
                  onClick={() => handleKeypadPress(digit)}
                  className="rounded-none border border-slate-200 bg-white py-2 text-xl font-bold text-slate-900 transition hover:border-blue-200 hover:text-blue-600"
                >
                  {digit}
                </button>
              ))}
            </div>

            <div className="mt-1.5 grid grid-cols-[1fr_1.7fr_1.15fr_1fr] gap-1.5">
              <button
                type="button"
                onClick={() => setQtyInput('')}
                className="rounded-none border border-slate-200 bg-white py-2 text-xl font-bold text-slate-500 transition hover:border-slate-300 hover:text-slate-700"
              >
                C
              </button>
              <button
                type="button"
                onClick={applyKeypadQuantity}
                className="rounded-none bg-emerald-500 py-2 text-base font-black text-white shadow-lg shadow-emerald-200 transition hover:bg-emerald-600"
              >
                ENTER
              </button>
              <button
                type="button"
                onClick={handleCheckout}
                disabled={cart.length === 0 || paying}
                className="rounded-none bg-violet-600 px-2 py-2 text-center text-xs font-black text-white shadow-lg shadow-violet-200 transition hover:bg-violet-700 disabled:cursor-not-allowed disabled:opacity-50"
              >
                <ReceiptText className="mx-auto mb-0.5 h-4 w-4" />
                {paying ? 'Saving' : 'Receipt'}
              </button>
              <button
                type="button"
                onClick={clearCart}
                disabled={cart.length === 0}
                className="rounded-none bg-red-500 px-2 py-2 text-center text-xs font-black text-white shadow-lg shadow-red-200 transition hover:bg-red-600 disabled:cursor-not-allowed disabled:opacity-50"
              >
                <Trash2 className="mx-auto mb-0.5 h-4 w-4" />
                Clear
              </button>
            </div>

            <div className="mt-3 grid grid-cols-3 gap-1.5">
              {[
                { label: 'Cash', value: 'Cash', icon: Banknote, activeClass: 'from-emerald-500 to-teal-500' },
                { label: 'ABA', value: 'ABA', icon: ReceiptText, activeClass: 'from-blue-500 to-indigo-500' },
                { label: 'Card', value: 'Card', icon: CreditCard, activeClass: 'from-slate-700 to-slate-900' },
              ].map((method) => {
                const active = payMethod === method.value;
                const Icon = method.icon;

                return (
                  <button
                    key={method.value}
                    type="button"
                    onClick={() => setPayMethod(method.value)}
                    className={`rounded-none border px-2 py-2.5 text-center text-xs font-bold transition ${active ? `border-transparent bg-gradient-to-r ${method.activeClass} text-white shadow-xl` : 'border-slate-200 bg-white text-slate-600 hover:border-slate-300'}`}
                  >
                    <Icon className="mx-auto mb-1 h-5 w-5" />
                    {method.label}
                  </button>
                );
              })}
            </div>
          </div>
        </aside>
      </div>

      {selectedProduct && (
        <div className="fixed inset-0 z-50 flex items-center justify-center px-4 bg-slate-950/45 backdrop-blur-sm">
          <div className="w-full max-w-md overflow-hidden rounded-none border border-white/70 bg-white shadow-[0_32px_80px_rgba(15,23,42,0.24)]">
            <div className="flex items-center justify-between px-6 py-5 border-b border-slate-200">
              <div>
                <h3 className="text-2xl font-black tracking-tight text-slate-900">{selectedProduct.productName}</h3>
                <p className="mt-1 text-sm text-slate-500">{getCategoryName(selectedProduct)}</p>
              </div>
              <button
                type="button"
                onClick={closeProductModal}
                className="inline-flex items-center justify-center w-10 h-10 transition rounded-none text-slate-400 hover:bg-slate-100 hover:text-slate-700"
              >
                <X className="w-6 h-6" />
              </button>
            </div>

            <div className="px-6 py-6 text-center">
              <div className="mx-auto mb-5 h-44 w-full max-w-xs overflow-hidden rounded-none bg-[linear-gradient(135deg,_#eff6ff_0%,_#f8fafc_55%,_#ecfeff_100%)]">
                {toAbsoluteImageUrl(selectedProduct.imageUrl) ? (
                  <img src={toAbsoluteImageUrl(selectedProduct.imageUrl)} alt={selectedProduct.productName} className="object-cover w-full h-full" />
                ) : (
                  <div className="flex items-center justify-center h-full text-slate-300">
                    <Package className="w-12 h-12" />
                  </div>
                )}
              </div>

              <p className="text-5xl font-black tracking-tight text-blue-600">{formatCurrency(getProductPrice(selectedProduct))}</p>
              <p className="mt-3 text-sm font-medium text-emerald-600">Stock available: {getProductStock(selectedProduct)}</p>

              <div className="flex items-center justify-center gap-3 mt-8">
                <button
                  type="button"
                  onClick={() => setModalQty((current) => Math.max(1, current - 1))}
                  className="inline-flex items-center justify-center transition bg-white border rounded-none shadow-sm h-14 w-14 border-slate-200 text-slate-700 hover:border-slate-300"
                >
                  <Minus className="w-6 h-6" />
                </button>
                <input
                  type="number"
                  min={1}
                  max={getProductStock(selectedProduct)}
                  value={modalQty}
                  onChange={(event) => {
                    const nextQty = Number(event.target.value);
                    if (Number.isNaN(nextQty)) {
                      return;
                    }

                    const stock = getProductStock(selectedProduct);
                    setModalQty(Math.min(stock, Math.max(1, nextQty)));
                  }}
                  onBlur={() => {
                    const stock = getProductStock(selectedProduct);
                    setModalQty((current) => Math.min(stock, Math.max(1, Number(current) || 1)));
                  }}
                  className="h-14 min-w-24 rounded-none border border-slate-200 bg-slate-50 px-3 text-center text-3xl font-black text-slate-900 outline-none [appearance:textfield] focus:border-blue-300 focus:ring-4 focus:ring-blue-100 [&::-webkit-inner-spin-button]:appearance-none [&::-webkit-outer-spin-button]:appearance-none"
                />
                <button
                  type="button"
                  onClick={() => setModalQty((current) => Math.min(getProductStock(selectedProduct), current + 1))}
                  className="inline-flex items-center justify-center text-blue-600 transition border border-blue-200 rounded-none shadow-sm h-14 w-14 bg-blue-50 hover:border-blue-300"
                >
                  <Plus className="w-6 h-6" />
                </button>
              </div>
            </div>

            <div className="grid grid-cols-2 gap-3 px-6 py-5 border-t border-slate-200">
              <button
                type="button"
                onClick={closeProductModal}
                className="px-5 py-4 text-lg font-bold transition bg-white border rounded-none border-slate-200 text-slate-600 hover:border-slate-300 hover:text-slate-900"
              >
                Cancel
              </button>
              <button
                type="button"
                onClick={() => {
                  addToCart(selectedProduct, modalQty);
                  closeProductModal();
                }}
                className="px-5 py-4 text-lg font-black text-white transition rounded-none shadow-xl bg-gradient-to-r from-blue-600 to-blue-500 shadow-blue-200 hover:from-blue-700 hover:to-blue-600"
              >
                Add to Cart
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default StaffPOS;
